const checkpoints = [];

const normalize = s => (s || '').trim().toLowerCase();

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const collections = JSON.parse(localStorage.getItem('project_collections') || '[]');
const items = JSON.parse(localStorage.getItem('project_collection_items') || '[]');

// Find the target collection by name
const targetCollection = collections.find(c => normalize(c.name) === normalize('Quick Reclaimed Wall Art')) || null;

// All qualifying projects per task criteria
const qualifyingProjects = projects.filter(p => {
  if (!p) return false;
  if (p.category !== 'Wall Art') return false;
  if (!Array.isArray(p.materialTags) || !p.materialTags.includes('Reclaimed Wood')) return false;
  if (typeof p.estimatedBuildTimeMinutes !== 'number' || p.estimatedBuildTimeMinutes > 180) return false;
  return true;
});
const qualifyingIds = qualifyingProjects.map(p => p.id);

// Determine top-rated among qualifying projects (by averageRating)
let maxRating = null;
for (const p of qualifyingProjects) {
  const r = typeof p.averageRating === 'number' ? p.averageRating : 0;
  if (maxRating === null || r > maxRating) maxRating = r;
}
if (maxRating === null) maxRating = 0;
const topRatedIds = qualifyingProjects.filter(p => (p.averageRating || 0) === maxRating).map(p => p.id);

let collectionItems = [];
let collectionProjects = [];
if (targetCollection) {
  collectionItems = items.filter(i => i.collectionId === targetCollection.id);
  collectionProjects = collectionItems
    .map(i => projects.find(p => p && p.id === i.projectId))
    .filter(Boolean);
}

// Projects in the collection that are both qualifying and top-rated
const collQualifyingTopProjects = collectionProjects.filter(p => qualifyingIds.includes(p.id) && topRatedIds.includes(p.id));

// Helper: are all projects in the collection qualifying & top-rated?
const allProjectsInCollectionQualifyingTop = collectionProjects.length > 0 && collectionProjects.every(p => qualifyingIds.includes(p.id) && topRatedIds.includes(p.id));

// CP1 (0.4): Collection exists with at least 1 project that is reclaimed-wood wall art under 3 hours AND top-rated among such projects
checkpoints.push({
  passed: !!targetCollection && collQualifyingTopProjects.length >= 1,
  weight: 0.4
});

// CP2 (0.3): Collection has at least 2 projects and every project in it is qualifying & top-rated
checkpoints.push({
  passed: !!targetCollection && collectionItems.length >= 2 && allProjectsInCollectionQualifyingTop,
  weight: 0.3
});

// CP3 (0.3): Collection has exactly 2 projects and both are qualifying & top-rated (no extra non-qualifying projects)
checkpoints.push({
  passed: !!targetCollection && collectionItems.length === 2 && allProjectsInCollectionQualifyingTop,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const parseDate = s => {
  if (!s) return null;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
};

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const comments = JSON.parse(localStorage.getItem('article_comments') || '[]');

// Last 3 months cutoff relative to 2026-03-03
const cutoff = new Date('2025-12-03T00:00:00Z');

// Qualifying beginner wood burning tutorials from last 3 months
const qualifyingArticles = articles.filter(a => {
  if (!a) return false;
  if (a.category !== 'Wood Burning') return false;
  if (a.contentType !== 'tutorial') return false;
  if (a.difficulty !== 'beginner') return false;
  const d = parseDate(a.createdAt);
  if (!d || d < cutoff) return false;
  return true;
});

const qualifyingIds = qualifyingArticles.map(a => a.id);

// Top-rated among qualifying tutorials
let maxRating = null;
for (const a of qualifyingArticles) {
  const r = typeof a.averageRating === 'number' ? a.averageRating : 0;
  if (maxRating === null || r > maxRating) maxRating = r;
}
if (maxRating === null) maxRating = 0;
const topRatedIds = qualifyingArticles.filter(a => (a.averageRating || 0) === maxRating).map(a => a.id);

const commentText = 'Planning to try this technique this weekend!';

// All comments with the exact required content
const allMatchingComments = comments.filter(c => c && c.content === commentText);

// Comments with required content on qualifying tutorials
const commentsOnQualifying = allMatchingComments.filter(c => qualifyingIds.includes(c.articleId));

// Comments with required content on top-rated qualifying tutorials
const commentsOnTopRated = allMatchingComments.filter(c => topRatedIds.includes(c.articleId));

// CP1 (0.5): At least one comment with the exact text on a beginner Wood Burning tutorial from the last 3 months
checkpoints.push({
  passed: commentsOnQualifying.length >= 1,
  weight: 0.5
});

// CP2 (0.3): At least one such comment is on a top-rated qualifying tutorial (by averageRating)
checkpoints.push({
  passed: commentsOnTopRated.length >= 1,
  weight: 0.3
});

// CP3 (0.2): The special comment text is not used on non-qualifying content (no misuse)
const allSpecialCommentsAreOnQualifying = allMatchingComments.length === 0 || allMatchingComments.every(c => qualifyingIds.includes(c.articleId));
checkpoints.push({
  passed: allSpecialCommentsAreOnQualifying,
  weight: 0.2
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const normalize = s => (s || '').trim().toLowerCase();

const categories = JSON.parse(localStorage.getItem('forum_categories') || '[]');
const subforums = JSON.parse(localStorage.getItem('forum_subforums') || '[]');
const threads = JSON.parse(localStorage.getItem('forum_threads') || '[]');
const posts = JSON.parse(localStorage.getItem('forum_posts') || '[]');

const targetTitleNorm = normalize('Advice on my first chisel set under $100');

// Find threads with the exact target title
const candidateThreads = threads.filter(t => normalize(t.title) === targetTitleNorm);

// Thread in the main Beginner Tools subforum
const targetThread = candidateThreads.find(t => t.subforumId === 'beginner_tools_main') || null;

// Check tags on the thread
let hasRequiredTags = false;
if (targetThread && Array.isArray(targetThread.tagNames)) {
  const tagsNorm = targetThread.tagNames.map(normalize);
  hasRequiredTags = tagsNorm.includes('chisels') && tagsNorm.includes('beginner');
}

// Find original post for this thread and check body text
const requiredSentence = 'I am looking for a beginner-friendly chisel set under $100 for small woodworking art projects.';
let bodyHasRequiredSentence = false;
if (targetThread) {
  const originalPost = posts.find(p => p.threadId === targetThread.id && p.isOriginalPost) || null;
  if (originalPost && typeof originalPost.content === 'string') {
    bodyHasRequiredSentence = originalPost.content.indexOf(requiredSentence) !== -1;
  }
}

// Verify the thread is indeed in the Beginner Tools category
let inBeginnerToolsCategory = false;
if (targetThread) {
  const subforum = subforums.find(sf => sf.id === targetThread.subforumId) || null;
  if (subforum) {
    const category = categories.find(c => c.id === subforum.categoryId) || null;
    if (category && category.name === 'Beginner Tools') {
      inBeginnerToolsCategory = true;
    }
  }
}

// CP1 (0.4): Thread with the exact title exists in Beginner Tools main subforum and has both 'chisels' and 'beginner' tags
checkpoints.push({
  passed: !!targetThread && hasRequiredTags,
  weight: 0.4
});

// CP2 (0.4): Original post body for this thread contains the required sentence about the chisel set and budget
checkpoints.push({
  passed: !!targetThread && bodyHasRequiredSentence,
  weight: 0.4
});

// CP3 (0.2): The thread is under the 'Beginner Tools' forum category (correct forum placement)
checkpoints.push({
  passed: !!targetThread && inBeginnerToolsCategory,
  weight: 0.2
});

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const normalize = s => (s || '').trim().toLowerCase();

const products = JSON.parse(localStorage.getItem('products') || '[]');
const wishlists = JSON.parse(localStorage.getItem('wishlists') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');

// Find the target wishlist by name
const targetWishlist = wishlists.find(w => normalize(w.name) === normalize('Gift Ideas')) || null;

let listItems = [];
let listProducts = [];
if (targetWishlist) {
  listItems = wishlistItems.filter(i => i.wishlistId === targetWishlist.id);
  listProducts = listItems
    .map(i => products.find(p => p && p.id === i.productId))
    .filter(Boolean);
}

// Products in the wishlist that meet the criteria
const qualifyingProducts = listProducts.filter(p => {
  if (!p) return false;
  if (p.category !== 'Wall Art') return false;
  if (typeof p.price !== 'number' || p.price >= 60) return false;
  return true;
});

// Total prices
const totalPriceAll = listProducts.reduce((sum, p) => sum + (p && typeof p.price === 'number' ? p.price : 0), 0);

// CP1 (0.3): 'Gift Ideas' wishlist exists and contains at least one wall art product under $60
checkpoints.push({
  passed: !!targetWishlist && qualifyingProducts.length >= 1,
  weight: 0.3
});

// CP2 (0.3): All products in the 'Gift Ideas' wishlist are wall art under $60 (no non-qualifying items)
const allItemsQualifying = listProducts.length > 0 && listProducts.every(p => p && p.category === 'Wall Art' && typeof p.price === 'number' && p.price < 60);
checkpoints.push({
  passed: !!targetWishlist && allItemsQualifying,
  weight: 0.3
});

// CP3 (0.4): The wishlist has exactly 3 items and their total price is at most $150
checkpoints.push({
  passed: !!targetWishlist && listItems.length === 3 && totalPriceAll <= 150 && allItemsQualifying,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const normalize = s => (s || '').trim().toLowerCase();

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Find the target reading list by name
const targetList = lists.find(l => normalize(l.name) === normalize('Beginner Practice Plan')) || null;

let listItems = [];
let listArticles = [];
if (targetList) {
  listItems = items.filter(i => i.readingListId === targetList.id);
  listArticles = listItems
    .map(i => articles.find(a => a && a.id === i.articleId))
    .filter(Boolean);
}

// Qualifying Carving and Joinery beginner posts under 20 minutes
const isQualifying = a => {
  if (!a) return false;
  if (a.difficulty !== 'beginner') return false;
  if (typeof a.estimatedReadingTimeMinutes !== 'number' || a.estimatedReadingTimeMinutes > 20) return false;
  if (a.category !== 'Carving' && a.category !== 'Joinery') return false;
  return true;
};

const carvingQual = listArticles.filter(a => isQualifying(a) && a.category === 'Carving');
const joineryQual = listArticles.filter(a => isQualifying(a) && a.category === 'Joinery');

const allItemsQualifying = listArticles.length > 0 && listArticles.every(a => isQualifying(a));

// CP1 (0.3): Reading list exists and has at least one qualifying beginner Carving or Joinery post under 20 minutes
checkpoints.push({
  passed: !!targetList && (carvingQual.length + joineryQual.length) >= 1,
  weight: 0.3
});

// CP2 (0.3): List contains at least 2 qualifying Carving and at least 2 qualifying Joinery posts
checkpoints.push({
  passed: !!targetList && carvingQual.length >= 2 && joineryQual.length >= 2,
  weight: 0.3
});

// CP3 (0.4): Reading list has exactly 4 items total and all 4 are qualifying (2 Carving + 2 Joinery)
checkpoints.push({
  passed: !!targetList && listItems.length === 4 && carvingQual.length >= 2 && joineryQual.length >= 2 && allItemsQualifying,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const artists = JSON.parse(localStorage.getItem('artists') || '[]');
const follows = JSON.parse(localStorage.getItem('artist_follows') || '[]');

// Qualifying geometric-style artists with at least 2 completed projects
const isGeometricStyle = a => {
  if (!a) return false;
  const primary = (a.primaryStyle || '').toLowerCase();
  const tags = Array.isArray(a.styleTags) ? a.styleTags.map(s => (s || '').toLowerCase()) : [];
  const styleLower = 'geometric';
  return primary === styleLower || tags.includes(styleLower);
};

const qualifyingArtists = artists.filter(a => isGeometricStyle(a) && (a.completedProjectCount || 0) >= 2);

// Sort by followerCount (most_followers), like listArtists
qualifyingArtists.sort((a, b) => (b.followerCount || 0) - (a.followerCount || 0));

const top2 = qualifyingArtists.slice(0, 2);
const top2Ids = top2.map(a => a.id);

// Helper to find follow record for an artist
const getFollow = artistId => follows.find(f => f.artistId === artistId) || null;

const followedTop2 = top2.filter(a => {
  const f = getFollow(a.id);
  return !!f;
});

const followedTop2WithProjectNotifications = top2.filter(a => {
  const f = getFollow(a.id);
  return f && f.notifyNewProjects === true;
});

// CP1 (0.4): At least one of the top 2 qualifying geometric artists is followed with new-project notifications enabled
checkpoints.push({
  passed: followedTop2WithProjectNotifications.length >= 1,
  weight: 0.4
});

// CP2 (0.3): Both of the top 2 qualifying geometric artists are followed (regardless of notification settings)
checkpoints.push({
  passed: top2Ids.length === 2 && followedTop2.length === top2Ids.length,
  weight: 0.3
});

// CP3 (0.3): Both of the top 2 qualifying geometric artists have notifyNewProjects enabled
checkpoints.push({
  passed: top2Ids.length === 2 && followedTop2WithProjectNotifications.length === top2Ids.length,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const normalize = s => (s || '').trim().toLowerCase();

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const projectMaterials = JSON.parse(localStorage.getItem('project_materials') || '[]');
const materialsLists = JSON.parse(localStorage.getItem('materials_lists') || '[]');
const materialsListItems = JSON.parse(localStorage.getItem('materials_list_items') || '[]');

// Identify the floating shelf project by category and keywords
const floatingProject = projects.find(p => {
  if (!p) return false;
  if (p.category !== 'Shelving') return false;
  const title = normalize(p.title);
  const desc = normalize(p.description);
  const haystack = title + ' ' + desc;
  return haystack.includes('floating shelf') && haystack.includes('hidden');
}) || null;

// All materials belonging to this project
const projectMats = floatingProject ? projectMaterials.filter(m => m.projectId === floatingProject.id) : [];
const projectMatIds = projectMats.map(m => m.id);

// Find a materials list named 'Floating Shelf Build List' tied to this project
const targetList = materialsLists.find(ml => normalize(ml.name) === normalize('Floating Shelf Build List') && (!floatingProject || ml.sourceProjectId === floatingProject.id)) || null;

let listItems = [];
if (targetList) {
  listItems = materialsListItems.filter(i => i.materialsListId === targetList.id);
}

// Items in the list that correspond to materials from the floating shelf project
const itemsFromProjectMaterials = listItems.filter(i => i && projectMatIds.includes(i.sourceProjectMaterialId));

// CP1 (0.3): A materials list named 'Floating Shelf Build List' exists and is associated with the floating shelf project
checkpoints.push({
  passed: !!floatingProject && !!targetList && targetList.sourceProjectId === floatingProject.id,
  weight: 0.3
});

// CP2 (0.3): At least one material from the floating shelf project has been added to this list
checkpoints.push({
  passed: !!floatingProject && !!targetList && itemsFromProjectMaterials.length >= 1,
  weight: 0.3
});

// CP3 (0.4): All materials defined for the floating shelf project are included in this materials list
checkpoints.push({
  passed: !!floatingProject && !!targetList && projectMatIds.length > 0 && itemsFromProjectMaterials.length >= projectMatIds.length,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const parseDate = s => {
  if (!s) return null;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
};

const events = JSON.parse(localStorage.getItem('events') || '[]');
const registrations = JSON.parse(localStorage.getItem('event_registrations') || '[]');

// Next calendar month relative to 2026-03-03 is April 2026
const startNext = new Date('2026-04-01T00:00:00Z');
const endNext = new Date('2026-04-30T23:59:59Z');

// Qualifying events per task criteria
const qualifyingEvents = events.filter(e => {
  if (!e) return false;
  if (e.format !== 'online') return false;
  if (e.topic !== 'Wood Carving') return false;
  if (e.difficulty !== 'beginner') return false;
  if (e.isWorkshop === false) return false;
  if (typeof e.price !== 'number' || e.price > 40) return false;
  const d = parseDate(e.startDateTime);
  if (!d || d < startNext || d > endNext) return false;
  return true;
});

const qualifyingIds = qualifyingEvents.map(e => e.id);

// Determine the cheapest qualifying event by price
let cheapestEvent = null;
for (const e of qualifyingEvents) {
  if (!cheapestEvent || (e.price || 0) < (cheapestEvent.price || 0)) {
    cheapestEvent = e;
  }
}

// Registrations for qualifying events with non-external payment methods
const nonExternalMethods = ['pay_later', 'pay_at_workshop'];
const registrationsOnQualifying = registrations.filter(r => r && qualifyingIds.includes(r.eventId) && nonExternalMethods.includes(r.paymentMethod));

// Registrations specifically for the cheapest qualifying event
const registrationsOnCheapest = registrationsOnQualifying.filter(r => cheapestEvent && r.eventId === cheapestEvent.id);

// CP1 (0.3): At least one registration for any qualifying event using a non-external, pay-later style payment method
checkpoints.push({
  passed: registrationsOnQualifying.length >= 1,
  weight: 0.3
});

// CP2 (0.4): At least one registration is specifically for the cheapest qualifying event (by price)
checkpoints.push({
  passed: !!cheapestEvent && registrationsOnCheapest.length >= 1,
  weight: 0.4
});

// CP3 (0.3): Every registration for the cheapest qualifying event uses a non-external payment method (no mistaken external payment for that event)
const allCheapestNonExternal = registrationsOnCheapest.length === 0 || registrationsOnCheapest.every(r => nonExternalMethods.includes(r.paymentMethod));
checkpoints.push({
  passed: !!cheapestEvent && allCheapestNonExternal && registrationsOnCheapest.length >= 1,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
